import logging
import json
import azure.functions as func


def main(req: func.HttpRequest) -> func.HttpResponse:
    """
    Azure Function HTTP API endpoint for a single-page application.
    Handles CORS preflight (OPTIONS) and standard API requests.
    """
    logging.info('Python HTTP trigger function processed a request.')

    # Define CORS headers - allow all origins for development flexibility
    cors_headers = {
        "Access-Control-Allow-Origin": "*",
        "Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, PATCH, OPTIONS",
        "Access-Control-Allow-Headers": "Content-Type, Authorization, X-Requested-With, Accept, Origin",
        "Access-Control-Max-Age": "86400",
        "Access-Control-Expose-Headers": "Content-Length, X-Request-Id"
    }

    # Handle CORS preflight OPTIONS request
    if req.method == "OPTIONS":
        return func.HttpResponse(
            status_code=204,
            headers=cors_headers
        )

    # Route handling based on method and path
    route = req.route_params.get("route", "")

    try:
        if req.method == "GET":
            response_data = handle_get(req, route)
        elif req.method == "POST":
            response_data = handle_post(req, route)
        elif req.method == "PUT":
            response_data = handle_put(req, route)
        elif req.method == "DELETE":
            response_data = handle_delete(req, route)
        elif req.method == "PATCH":
            response_data = handle_patch(req, route)
        else:
            response_data = {
                "error": f"Method {req.method} not supported",
                "status": 405
            }
            return func.HttpResponse(
                body=json.dumps(response_data),
                status_code=405,
                headers={**cors_headers, "Content-Type": "application/json"}
            )

        status_code = response_data.pop("status", 200)

        return func.HttpResponse(
            body=json.dumps(response_data),
            status_code=status_code,
            headers={**cors_headers, "Content-Type": "application/json"}
        )

    except ValueError as ve:
        logging.error(f"Validation error: {str(ve)}")
        error_response = {
            "error": "Bad Request",
            "message": str(ve)
        }
        return func.HttpResponse(
            body=json.dumps(error_response),
            status_code=400,
            headers={**cors_headers, "Content-Type": "application/json"}
        )
    except Exception as e:
        logging.error(f"Internal server error: {str(e)}")
        error_response = {
            "error": "Internal Server Error",
            "message": "An unexpected error occurred"
        }
        return func.HttpResponse(
            body=json.dumps(error_response),
            status_code=500,
            headers={**cors_headers, "Content-Type": "application/json"}
        )


def handle_get(req: func.HttpRequest, route: str) -> dict:
    """Handle GET requests."""
    logging.info(f"GET request for route: {route}")

    # Example: Parse query parameters
    name = req.params.get("name")
    page = req.params.get("page", "1")
    limit = req.params.get("limit", "10")

    if route == "health":
        return {
            "status": 200,
            "message": "API is healthy",
            "service": "spa-api"
        }

    if route == "items":
        # Example items endpoint
        items = [
            {"id": 1, "name": "Item 1", "description": "First item"},
            {"id": 2, "name": "Item 2", "description": "Second item"},
            {"id": 3, "name": "Item 3", "description": "Third item"},
        ]
        return {
            "status": 200,
            "data": items,
            "pagination": {
                "page": int(page),
                "limit": int(limit),
                "total": len(items)
            }
        }

    if route == "user":
        return {
            "status": 200,
            "data": {
                "id": 1,
                "name": name or "Anonymous",
                "email": "user@example.com"
            }
        }

    return {
        "status": 200,
        "message": f"GET request received for route: {route or 'root'}",
        "params": dict(req.params)
    }


def handle_post(req: func.HttpRequest, route: str) -> dict:
    """Handle POST requests."""
    logging.info(f"POST request for route: {route}")

    try:
        request_body = req.get_json()
    except ValueError:
        raise ValueError("Request body must be valid JSON")

    if route == "items":
        # Validate required fields
        if not request_body.get("name"):
            raise ValueError("Field 'name' is required")

        new_item = {
            "id": 100,  # In production, generate a real ID
            "name": request_body.get("name"),
            "description": request_body.get("description", ""),
            "created": True
        }
        return {
            "status": 201,
            "message": "Item created successfully",
            "data": new_item
        }

    if route == "auth/login":
        username = request_body.get("username")
        password = request_body.get("password")

        if not username or not password:
            raise ValueError("Username and password are required")

        # In production, validate credentials properly
        return {
            "status": 200,
            "message": "Login successful",
            "data": {
                "token": "example-jwt-token-replace-with-real-auth",
                "user": {"username": username}
            }
        }

    return {
        "status": 200,
        "message": f"POST request received for route: {route or 'root'}",
        "received_data": request_body
    }


